private validateDetails(details?: SurchargeDetail[]) {
    if (!details) return;
    if (details.length === 0) {
      throw new BusinessLogicError(ErrorCode.AGE_RANGE_INVALID);
    }
    const normalized = this.normalizeDetails(details);
    if (!normalized || normalized.length === 0) return;

    let globalMinFrom: number | null = null;
    let globalMaxTo: number | null = null;
    let previousFrom: number | null = null;
    let previousTo: number | null = null;
    for (const detail of normalized) {
      if (!Number.isFinite(detail.fromAge) || !Number.isFinite(detail.toAge)) {
        throw new BusinessLogicError(ErrorCode.AGE_RANGE_INVALID);
      }
      if (detail.fromAge >= detail.toAge) {
        throw new BusinessLogicError(ErrorCode.AGE_RANGE_INVALID);
      }
      if (!Number.isFinite(detail.amount)) {
        throw new BusinessLogicError(ErrorCode.AGE_RANGE_INVALID);
      }
      if (previousFrom !== null && detail.fromAge === previousFrom && detail.toAge === previousTo) {
        throw new BusinessLogicError(ErrorCode.AGE_RANGE_INVALID);
      }
      globalMinFrom = globalMinFrom === null ? detail.fromAge : Math.min(globalMinFrom, detail.fromAge);
      globalMaxTo = globalMaxTo === null ? detail.toAge : Math.max(globalMaxTo, detail.toAge);
      previousFrom = detail.fromAge;
      previousTo = detail.toAge;
    }

    const allSorted = [...normalized].sort((a, b) => a.fromAge - b.fromAge);
    if (allSorted[0].fromAge !== 0) {
      throw new BusinessLogicError(ErrorCode.AGE_RANGE_INVALID);
    }
    let currentTo = allSorted[0].toAge;
    for (let i = 1; i < allSorted.length; i += 1) {
      const range = allSorted[i];
      if (range.fromAge > currentTo + 1) {
        throw new BusinessLogicError(ErrorCode.AGE_RANGE_INVALID);
      }
      if (range.fromAge <= currentTo) {
        throw new BusinessLogicError(ErrorCode.AGE_RANGE_INVALID);
      }
      currentTo = range.toAge;
    }
  }
